## 修正されたコード例

```javascript
const express = require('express');
const app = express();
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');

// 環境変数から取得
const SECRET = process.env.JWT_SECRET || (() => {
  throw new Error('JWT_SECRET environment variable is required');
})();

// リクエスト本体解析
app.use(express.json());

// 認証ミドルウェア
const verifyToken = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  jwt.verify(token, SECRET, (err, decoded) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid token' });
    }
    req.user = decoded;
    next();
  });
};

// セキュアなログイン
app.post('/login', [
  body('username').trim().notEmpty().isLength({ max: 50 }),
  body('password').notEmpty().isLength({ min: 1, max: 500 })
], async (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ error: 'Invalid input' });
  }

  const { username, password } = req.body;

  // データベースからユーザーを検索し、パスワードを検証
  // const user = await User.findOne({ username });
  // if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
  //   return res.status(401).json({ error: 'Invalid credentials' });
  // }

  const token = jwt.sign({ id: 'user.id', username }, SECRET, { expiresIn: '1h' });
  res.json({ token });
});

// セキュアなユーザー取得
app.get('/user/:id', verifyToken, (req, res) => {
  const userId = parseInt(req.params.id, 10);

  if (isNaN(userId) || userId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }

  // 自身のデータのみ取得可能
  if (req.user.id !== userId) {
    return res.status(403).json({ error: 'Unauthorized' });
  }

  const query = 'SELECT id, username, email FROM users WHERE id = ?';
  db.query(query, [userId], (err, result) => {
    if (err) {
      console.error('Database error:', err);
      return res.status(500).json({ error: 'Internal server error' });
    }
    res.json(result);
  });
});

// セキュアなエラーハンドリング
app.use((err, req, res, next) => {
  console.error('Error:', err);

  const isDevelopment = process.env.NODE_ENV === 'development';
  res.status(500).json({
    error: 'Internal server error',
    ...(isDevelopment && { message: err.message })
  });
});

app.listen(3000, () => console.log('Server running on port 3000'));
```

